// ─── Scoring ─────────────────────────────────────────────────────────────────
function calcScore({ hasMatric, hasDegree, hasVehicle, networkSize, salesYears }) {
  let s = 0;
  if (hasMatric) s += hasDegree ? 20 : 12;
  if (hasVehicle) s += 30;
  s += { ">200": 30, "100-200": 22, "50-100": 15, "<50": 5 }[networkSize] || 0;
  s += { ">5": 20, "3-5": 15, "1-3": 10, "<1": 4 }[salesYears] || 0;
  return Math.min(s, 100);
}
function getTier(score) {
  if (score >= 80) return { label: "Gold",   color: GOLD,   emoji: "🥇", desc: "Top Tier Candidate — Fast Track Eligible" };
  if (score >= 55) return { label: "Silver", color: SILVER, emoji: "🥈", desc: "Strong Candidate — Recommend Interview" };
  return             { label: "Bronze", color: "#A0785A", emoji: "🥉", desc: "Developing Profile — Nurture Pipeline" };
}

// ─── Commission Logic ─────────────────────────────────────────────────────────
// Life & Risk:        (policies × R1,000 avg premium × 12 months) × 65% upfront
//                     + policies × R1,000 × 2.5% monthly trail (passive, recurring)
// Retirement Annuity: (RAs × R1,500 avg premium × 12 months) × 3% upfront
//                     (no trail modelled for RA in this version)
// Lump Sum Invest:    lump sum value × 1.5% once-off upfront
//
// Annual Projection:  (Monthly upfronts × 12) + (monthly trail × 12 retention kicker)
// The "12-month kicker" represents growing book value — trail compounds as more
// policies are retained each month, approximated as trail × 12 for Year 1 total.
function calcEarnings({ lifeRisk, retirementAnnuities, lumpSum }) {
  const lifeUpfront  = (lifeRisk * 1000 * 12) * 0.65;
  const lifeTrail    = lifeRisk * 1000 * 0.025;          // per month, passive
  const raUpfront    = (retirementAnnuities * 1500 * 12) * 0.03;
  const lumpUpfront  = lumpSum * 0.015;
  const totalUpfront = lifeUpfront + raUpfront + lumpUpfront;
  const monthlyTrail = lifeTrail;
  const annualTrailKicker = monthlyTrail * 12;
  const projectedAnnual   = (totalUpfront * 12) + annualTrailKicker;
  return { totalUpfront, monthlyTrail, annualTrailKicker, projectedAnnual,
           lifeUpfront, raUpfront, lumpUpfront };
}

// ─── FA Success Meter ─────────────────────────────────────────────────────────
// Benchmarks (industry averages for SA Liberty/In8 field advisors):
//   Life & Risk:  avg new FA ~ 4 policies/month, top performer ~ 15+
//   RA:           avg new FA ~ 2/month,           top performer ~ 8+
//   Lump Sum:     avg new FA ~ R50k/month,         top performer ~ R250k+
// Weighted score 0–100 → rank label
function calcFARank({ lifeRisk, retirementAnnuities, lumpSum }) {
  // Life & Risk: 0–15+ policies/month → 0–40pts (industry avg = 4, top = 15)
  const lifeScore = Math.min(lifeRisk / 15, 1) * 40;
  // RA:          0–8+ RAs/month      → 0–35pts (industry avg = 2, top = 8)
  const raScore   = Math.min(retirementAnnuities / 8, 1) * 35;
  // Lump Sum:    step-function based on Envestpro thresholds
  //   <R50,000   → no meaningful impact  (0pts)
  //   R50k–R99k  → slight change         (8pts)
  //   R100k–R199k→ reasonable change     (18pts)
  //   R200k+     → considerable change   (25pts)
  let lumpScore = 0;
  if      (lumpSum >= 200000) lumpScore = 25;
  else if (lumpSum >= 100000) lumpScore = 18;
  else if (lumpSum >= 50000)  lumpScore = 8;
  // else lumpScore stays 0 (below R50k = no impact as specified)

  const total = Math.round(lifeScore + raScore + lumpScore);
  let rank, color, icon, msg;
  if      (total >= 85) { rank = "Elite Performer"; color = "#FFD700"; icon = "🏆"; msg = "Top 5% nationally. Exceptional commitment — the hallmark of a future top biller." }
  else if (total >= 65) { rank = "High Performer";  color = GOLD;      icon = "⭐"; msg = "Above industry average. Strong closing mindset — you'll build a quality book quickly." }
  else if (total >= 40) { rank = "Solid Starter";   color = GOLD_L;    icon = "📈"; msg = "On par with the industry average new FA. Growth trajectory looks positive." }
  else if (total >= 20) { rank = "Developing FA";   color = SILVER;    icon = "🌱"; msg = "Below average benchmarks. Consider whether your network and drive match the targets." }
  else                  { rank = "Early Stage";      color = "#A0785A"; icon = "💡"; msg = "Very modest targets set. This is a full-commission career — realistic targets are key to success." }
  return { total, rank, color, icon, msg };
}

