// ─── Touch-optimised Slider ───────────────────────────────────────────────────
// Uses a native <input type="range"> with full CSS styling so mobile touch
// is responsive without any custom pointer-event calculation.
function Slider({ label, value, min, max, onChange, unit = "" }) {
  const pct = max === min ? 0 : ((value - min) / (max - min)) * 100;
  const displayVal = unit === "R" ? `R${value.toLocaleString()}` : `${value}${unit}`;
  return (
    <div style={{ marginBottom: "1.5rem" }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.6rem" }}>
        <span style={{ color: WHITE, fontFamily: "'Playfair Display', serif", fontSize: "0.85rem" }}>{label}</span>
        <span style={{ color: GOLD, fontWeight: 700, fontFamily: "'Playfair Display', serif", fontSize: "1rem" }}>{displayVal}</span>
      </div>
      {/* Visible track */}
      <div style={{ position: "relative", height: "36px", display: "flex", alignItems: "center" }}>
        <div style={{ position: "absolute", left: 0, right: 0, height: "8px", borderRadius: "4px", background: "rgba(255,255,255,0.1)", overflow: "hidden" }}>
          <div style={{ width: `${pct}%`, height: "100%", background: `linear-gradient(90deg, ${GOLD}, ${GOLD_L})`, transition: "width 0.05s" }} />
        </div>
        {/* Thumb dot (visual only, pointer-events:none) */}
        <div style={{
          position: "absolute", left: `calc(${pct}% - 11px)`,
          width: "22px", height: "22px", borderRadius: "50%",
          background: `linear-gradient(135deg, ${GOLD}, ${GOLD_L})`,
          boxShadow: `0 0 10px rgba(201,146,42,0.7)`,
          border: "2px solid #fff", pointerEvents: "none",
          transition: "left 0.05s",
        }} />
        {/* Native range on top — fully opaque, sized to fill touch area */}
        <input type="range" min={min} max={max} value={value}
          onChange={e => onChange(Number(e.target.value))}
          style={{
            position: "absolute", left: 0, right: 0, width: "100%",
            height: "36px", opacity: 0, cursor: "pointer",
            margin: 0, padding: 0, touchAction: "manipulation",
            WebkitAppearance: "none", appearance: "none",
          }}
        />
      </div>
    </div>
  );
}

