// ─── FA Success Meter Component ───────────────────────────────────────────────
function FASuccessMeter({ lifeRisk, retirementAnnuities, lumpSum }) {
  const { total, rank, color, icon, msg } = calcFARank({ lifeRisk, retirementAnnuities, lumpSum });
  const sectors = [
    { label: "Early Stage", minPct: 0,  maxPct: 20,  activeColor: "#A0785A" },
    { label: "Developing",  minPct: 20, maxPct: 40,  activeColor: SILVER },
    { label: "Solid",       minPct: 40, maxPct: 65,  activeColor: GOLD_L },
    { label: "High",        minPct: 65, maxPct: 85,  activeColor: GOLD },
    { label: "Elite",       minPct: 85, maxPct: 100, activeColor: "#FFD700" },
  ];
  return (
    <div style={{
      background: "rgba(255,255,255,0.04)", border: `1px solid ${color}44`,
      borderRadius: "16px", padding: "1.25rem", marginBottom: "1rem",
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.75rem" }}>
        <div style={{ color: GOLD, fontSize: "0.68rem", letterSpacing: "0.08em", textTransform: "uppercase" }}>FA Success Meter</div>
        <div style={{ display: "flex", alignItems: "center", gap: "0.35rem" }}>
          <span style={{ fontSize: "1.1rem" }}>{icon}</span>
          <span style={{ color, fontFamily: "'Playfair Display', serif", fontWeight: 700, fontSize: "0.9rem" }}>{rank}</span>
        </div>
      </div>
      {/* Segmented bar */}
      <div style={{ display: "flex", gap: "3px", marginBottom: "0.5rem", height: "12px", borderRadius: "6px", overflow: "hidden" }}>
        {sectors.map(({ label: sl, minPct, maxPct, activeColor }) => {
          const isActive = total >= minPct;
          const segWidth = maxPct - minPct;
          return (
            <div key={sl} style={{
              flex: segWidth, height: "100%", borderRadius: "3px",
              background: isActive ? activeColor : "rgba(255,255,255,0.08)",
              transition: "background 0.4s ease",
            }} />
          );
        })}
      </div>
      {/* Labels */}
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.75rem" }}>
        {sectors.map(({ label: sl }) => (
          <span key={sl} style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.58rem" }}>{sl}</span>
        ))}
      </div>
      {/* Message */}
      <div style={{
        background: `${color}18`, border: `1px solid ${color}44`,
        borderRadius: "10px", padding: "0.6rem 0.8rem",
      }}>
        <p style={{ color: WHITE, fontSize: "0.78rem", lineHeight: 1.55, margin: 0 }}>{msg}</p>
      </div>
      {/* Benchmark comparison */}
      <div style={{ display: "flex", gap: "0.5rem", marginTop: "0.75rem" }}>
        {[
          { label: "Life & Risk", val: lifeRisk, avg: 4, unit: "/mo" },
          { label: "RA", val: retirementAnnuities, avg: 2, unit: "/mo" },
          { label: "Lump Sum", val: `R${(lumpSum/1000).toFixed(0)}k`, avg: "R50k", unit: "" },
        ].map(({ label: bl, val, avg, unit: u }) => (
          <div key={bl} style={{ flex: 1, background: "rgba(255,255,255,0.04)", borderRadius: "8px", padding: "0.5rem", textAlign: "center" }}>
            <div style={{ color: SILVER, fontSize: "0.6rem", marginBottom: "0.2rem" }}>{bl}</div>
            <div style={{ color: GOLD, fontFamily: "'Playfair Display', serif", fontWeight: 700, fontSize: "0.85rem" }}>{val}{u}</div>
            <div style={{ color: "rgba(255,255,255,0.25)", fontSize: "0.55rem" }}>avg {avg}{u}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

