    if (hasSAID  === false) onKnockout("Unfortunately, a valid South African ID is a legal requirement for FAIS licensing. We look forward to assisting South African citizens.");
    if (hasMatric === false) onKnockout("A Matric certificate is the minimum educational requirement. Consider completing your NSC and applying again.");
    if (hasVehicle === false) onKnockout("Field-based client visits are essential to this role. A valid driver's licence and own vehicle are required.");
    if (hasLaptop === false) onKnockout("A laptop or computer is required to manage your client portfolio and complete regulatory submissions.");
